import{_ as a,o as t,c as o,ae as n}from"./chunks/framework.B6gjLfeO.js";const p=JSON.parse('{"title":"Facebook Ads FAQ","description":"","frontmatter":{"title":"Facebook Ads FAQ","slug":"facebook-ads-faq"},"headers":[],"relativePath":"marketer-hub/facebook-ads-faq.md","filePath":"marketer-hub/facebook-ads-faq.md"}'),s={name:"marketer-hub/facebook-ads-faq.md"};function r(i,e,h,c,l,d){return t(),o("div",null,[...e[0]||(e[0]=[n('<p>The most frequently asked questions about Facebook ads.</p><details><summary>What is Facebook MMP?</summary><p>The acronym MMP is used to mean either the broad category of Facebook Mobile Marketing Partners, or more narrowly to mean Mobile Measurement Partners. The latter is a special subset of Facebook partners that have access to device-level attribution data. Branch has been vetted by Facebook and joined this group of partners in order to provide both granular analytics and true cross-channel reporting. We help you measure which installs, opens and conversion events should be attributed to Facebook ad campaigns versus other marketing efforts.</p></details><details><summary>How does Branch attribute events to Facebook ads?</summary><p>Facebook is a self-attributing network. This means that Facebook claims credit for installs and other events. This differs from some ad networks, which send a stream of impressions and clicks that Branch then matches to events. Branch then compares these claims against other ad networks, as well as traffic coming from email, your website, and other sources, choosing the most recent click to get credit.</p><p>The Branch SDK already helps you track installs and other events. When you enable the Facebook MMP integration, Branch sends events and advertising IDs to Facebook. Facebook then reports whether devices previously viewed or clicked a Facebook ad, including helpful information such as campaign, ad set, and ad. As stated above, Branch then dedupes these claims against other claims for attribution.</p></details><details><summary>Do I need the Facebook SDK in order for Branch to attribute installs, opens, and other events back to Facebook?</summary><p>No, the Branch SDK collects adequate information in order to attribute events back to Facebook ads.</p></details><details><summary>How can I use deep links in Facebook ads?</summary><p>Make sure you <a href="https://help.branch.io/v1/docs/facebook-app-install-ads#enable-facebook-as-an-ad-partner-for-measurement" target="_blank" rel="noreferrer">set up the integration with Facebook MMP</a> in Branch. Then navigate to the <a href="https://dashboard.branch.io/ads/partner-management/a_facebook?tab=settings" target="_blank" rel="noreferrer">Facebook page under Partner management</a> and select <strong>Create Facebook Link</strong>.</p><p>Longer instructions can be found in the guides linked to from the <a href="https://help.branch.io/v1/docs/facebook-ads-overview" target="_blank" rel="noreferrer">Facebook overview</a> page. For example, see <a href="https://help.branch.io/v1/docs/facebook-app-install-ads#create-an-ad-link-for-deep-linking" target="_blank" rel="noreferrer">this section of the App Installs guide</a>.</p></details><details><summary>How can I attribute conversion events to Facebook ads?</summary><p>First, make sure you have <a href="https://help.branch.io/v1/docs/facebook-app-install-ads#enable-facebook-as-an-ad-partner-for-measurement" target="_blank" rel="noreferrer">set up the integration with Facebook MMP</a> in Branch. Second, <a href="https://help.branch.io/developers-hub/docs/track-branch-events#standard-events" target="_blank" rel="noreferrer">set up tracking for Standard Events</a>. We will automatically attribute events to Facebook ads.</p><p>Facebook will not accept custom event names over 40 characters or those that start with a hyphen, and will only accept letters, numbers, hyphens, spaces, and underscores. Branch will automatically truncate event names over 40 characters and may further sanitize your event names to help ensure they pass validation. For example:</p><ul><li><strong>Event name entered</strong>: This &amp; Is &amp; A * Bad Event That&#39;s So SO SOOOOOO Long</li><li><strong>Sanitized by Branch to</strong>: This Is A <em>Bad Event That</em>s So SO S</li></ul><p>There are advanced options for tracking events, which you can read more about <a href="https://help.branch.io/v1/docs/facebook-faq-and-advanced-options#facebook-mmp-event-options" target="_blank" rel="noreferrer">here</a>.</p></details><details><summary>What are the permissions you ask for as part of the onboarding process, and why?</summary><table tabindex="0"><thead><tr><th>Permissions (OAuth scopes)</th><th>Why</th></tr></thead><tbody><tr><td><code>ads_read</code></td><td>Pulling marketing insights data (e.g. impressions, clicks, cost) to present in Branch. Also used for pulling creative name and id, etc., to provide richer analytics for installs, opens and other events.</td></tr><tr><td><code>ads_management</code></td><td>Required to upload/create audiences.</td></tr></tbody></table></details><details><summary>What is each piece of information needed during the onboarding process, and why?</summary><table tabindex="0"><thead><tr><th>Identifier</th><th>Why</th></tr></thead><tbody><tr><td>Ad account</td><td>Pulling marketing insights data (e.g. impressions, clicks, cost) to present on the Branch Dashboard.</td></tr><tr><td>Facebook App ID</td><td>Sending installs, opens and other events to Facebook in order to see whether they were driven by a Facebook ad campaign.</td></tr><tr><td>Facebook App Secret (Optional)</td><td>Used to create an app access token for deferred deep linking. The secret is not stored anywhere.</td></tr></tbody></table></details><details><summary>Why can’t I see the ad account I want to use?</summary><p>Please try logging out and logging back in on Facebook. Note the email address that you use. If you still do not see ad accounts, please visit <a href="http://business.facebook.com" target="_blank" rel="noreferrer">business.facebook.com</a> and ensure that you use the same email address / Facebook account.</p></details><details><summary>Does Branch provide view-through (impression) attribution for Facebook?</summary><p>Branch is able to provide device-level view-through attribution for installs only, for up to 24 hours from impression to install. This is what is available via the MMP API that Facebook has exposed. It&#39;s also possible that if other app events (such as opens) occur shortly after an install, we can attribute those back to the same impression/view.</p><p>Facebook does not allow us to use impression trackers. Facebook will only provide impression data for certain app events via MMP API. Thus, we will not be able to track the large majority of web conversions attributed to a Facebook impression. This is specifically not allowed by Facebook. There unfortunately aren&#39;t any workarounds to this.</p></details><details><summary>Why is Facebook no longer enabled?</summary><p>We&#39;ve hidden the old Facebook setup flow. Please choose &quot;Connect with Facebook&quot; and follow the guide to <a href="https://help.branch.io/v1/docs/facebook-app-install-ads#enable-facebook-as-an-ad-partner-for-measurement" target="_blank" rel="noreferrer">set up the integration with Facebook MMP</a>.</p></details><details><summary>What happens to campaigns in which I&#39;m using deep links?</summary><p>We still highly recommend you use links in ads. <a href="https://branch.io/resources/#case-studies" target="_blank" rel="noreferrer">Studies have shown</a> that when you deep link your users, they have a better experience and retention is higher.</p><p>When you put a Branch link in a Facebook ad, we still return this link to your app, so that users can be deep linked. Deep linking functions exactly as it did before.</p></details><details><summary>Do I need to remove deep links from my Facebook ads?</summary><p>No. We recommend you use deep links in your Facebook ads.</p></details><details><summary>Does this new Facebook MMP functionality cover web campaigns?</summary><p>Generally, no. Facebook MMP allows us to measure Facebook app install and app engagement ads. However, in some cases, we are able to attribute web events that occur after an app install/engagement ad back to that ad. This is because we can link together web and app user identifiers as part of our People-Based Attribution product.</p></details><details><summary>Why does the data on Facebook and the data on Branch not line up?</summary><p>Please see <a href="https://help.branch.io/faq/docs/sources-of-discrepancies-between-facebook-and-branch" target="_blank" rel="noreferrer">Sources of Discrepancies between Facebook and Branch</a>.</p></details><details><summary>How can I change the authentication user ID for Facebook/Google Ads integration on Branch?</summary><p>To change the user authentication access for Facebook/Google ads in Branch:</p><ol><li>Re-authenticate the integration from your Branch dashboard via the account you want the access for.</li><li>If the changes are not reflected, disable and re-enable the integration which would require inserting the initial details required.</li></ol></details><details><summary>When I change a campaign name on Facebook, will that apply in Branch immediately or when an engagement on the ad starts?</summary><p>After changing the campaign name on Facebook, all new conversions from that campaign will get reflected under the new campaign name in Branch. However, any previously recorded conversions from the same campaign would still show under the old campaign name.</p></details><h3 id="advanced-options-faqs" tabindex="-1">Advanced options FAQs <a class="header-anchor" href="#advanced-options-faqs" aria-label="Permalink to &quot;Advanced options FAQs&quot;">​</a></h3><details><summary>What are the Facebook MMP event options?</summary><p>Branch + Facebook MMP allows you to attribute events back to your Facebook ad campaigns. Branch sends events to Facebook, along with metadata including advertising ID. Facebook then returns info on the ad that the user last viewed or clicked, if any. Branch then surfaces this on our Dashboard, and conditionally* makes this data available in our <a href="https://help.branch.io/v1/docs/data-feeds-overview" target="_blank" rel="noreferrer">Data Feeds</a> product.</p><p>Partners have several options when it comes to sending events to Facebook.</p><p>You must have signed the <a href="https://www.facebook.com/ads/manage/advanced_mobile_measurement/app_based_tos/" target="_blank" rel="noreferrer">Data Use Terms for Advanced Mobile App Measurement</a>.</p></details><details><summary>How do I track installs with Facebook?</summary><p>Branch sends all installs to Facebook. Facebook de-duplicates installs on their end. If you have the Facebook SDK and/or another MMP, these also send installs to Facebook&#39;s backend. This will not result in duplicate installs, since Facebook de-dupes them.</p></details><details><summary>How can I track reinstalls and opens with Facebook?</summary><p>Facebook does not de-duplicate custom app events on their backend. So if you have the Facebook SDK integrated or another MMP tracking app opens, choose the first option below.</p><p>When tracking reinstalls and opens, you have three options:</p><ol><li><em>use Branch name (branch_open)</em>: This allows us to get attribution data from Facebook, but without it counting as an app open. Use this option if you have the Facebook SDK integrated or are testing with another MMP. Since the Facebook SDK or other MMP is already sending fb_mobile_activate_app, you do not want Branch to send this a second time. (Default)</li><li><em>use Facebook name (fb_mobile_activate_app)</em>: Branch will send the exact event used by Facebook for tracking app opens. Use this option if you do not have the Facebook SDK and you are not tracking opens with another MMP, and you would like Branch to help Facebook record opens.</li><li><em>disable</em>: Use this option if you do not want Branch attributing opens at all. In some cases, we may still be able to attribute opens based on previously retrieved attribution data from Facebook. But we will not send any opens to Facebook in order to get attribution data back.</li></ol></details><details><summary>How do I track other conversion events with Facebook?</summary><p>Facebook does not de-duplicate custom app events on their backend. If you are tracking conversion events with the Facebook SDK or another MMP, choose option 1 below.</p><p>It&#39;s possible to track app events using only Branch. You can <a href="https://help.branch.io/developers-hub/docs/track-branch-events" target="_blank" rel="noreferrer">track the events</a> with Branch once, and then we send them to Facebook as well as other analytics systems. Use the <a href="https://help.branch.io/v1/docs/facebook-faq-and-advanced-options" target="_blank" rel="noreferrer">v2/event logging methods outlined here</a>.</p><p>When tracking add to cart, purchase, and other Facebook app events, you have 3 options:</p><ol><li><strong>use Branch name</strong>: This allows us to get attribution data from Facebook, but without it counting as a purchase, add to cart, etc. Use this option if you have the Facebook SDK integrated or are testing with another MMP, and you already track app events via one of those two methods. Since the Facebook SDK or other MMP is already sending events to Facebook, you do not want Branch to send these a second time. (Default)</li><li><strong>use Facebook name</strong>: Branch will send the exact event used by Facebook for tracking app events. Use this option if you are not already tracking app events with the Facebook SDK or another MMP, and you would like Branch to help Facebook record these events.</li><li><strong>disable</strong>: Use this option if you do not want Branch attributing these conversion events. In some cases, we may still be able to attribute these conversion events based on previously retrieved attribution data from Facebook. But we will not send any conversion events to Facebook in order to get attribution data back.</li></ol></details><details><summary>How do I track custom events with Facebook?</summary><p>In addition to tracking installs and Facebook app events (see <a href="./track-custom-events-with-facebook.html">Tracking other conversion events</a> above), you can also have Branch attribute custom events. To do so, we must send those events to Facebook.</p><p>When tracking custom events that have no equivalent <a href="./track-other-conversion-events-with-facebook.html">Facebook App Event</a>, you have 2 options:</p><ol><li><em>enable</em>: Branch will send custom events to Facebook. this allows us to get attribution data from Facebook. (default)</li><li><em>disable</em>: Use this option if you do not want Branch attributing custom events. In some cases, we may still be able to attribute these custom events based on previously retrieved attribution data from Facebook. But we will not send any custom events to Facebook in order to get attribution data back.</li></ol></details><details><summary>How do I migrate from the existing Facebook integration to MMP?</summary><p>You can no longer see the previous Facebook onboarding flow that required you to copy-paste your Facebook app secret. Please use the <strong>Authenticate with Facebook</strong> option instead.</p><p>If you have been using our integration with Facebook prior to February 14, 2018, then we highly recommend that you upgrade to our new integration that includes MMP.</p><p>We are now certified by Facebook as a Mobile Measurement Partner! Branch can now help you attribute installs, opens, and conversion events to Facebook like never before.</p><p>This integration includes full support for Facebook, Instagram, and the Audience Network. We also automatically pull in impressions and clicks from Facebook and surface those alongside your clicks on Branch Links. The deep linking experience your users love is still supported.</p><p>Instructions on how to get set up with Facebook MMP are <a href="./facebook-app-install-ads.html#enable-facebook-as-an-ad-partner-for-measurement">here</a>. Note that this will replace your existing credentials on our backend. Instead of copy-pasting your Facebook app secret into the Branch Dashboard, you can now simply click through the normal Facebook login flow.</p><p>Branch will now automatically surface Facebook campaign, ad set, and ad information on the Branch Dashboard&#39;s visualizations! This isn&#39;t limited to <a href="https://dashboard.branch.io/ads/analytics" target="_blank" rel="noreferrer">Ads Analytics</a> -- it also includes cross-channel analytics such as <a href="https://dashboard.branch.io/sources" target="_blank" rel="noreferrer">Source Analytics</a>.</p></details><details><summary>What are the sources of discrepancies between Facebook and Branch?</summary><p>When using Branch as your Facebook MMP, you may notice some data discrepancies between the Branch dashboard and the Facebook dashboard if not configured correctly. We have highlighted several sources of discrepancies if they are present after you have onboarded with Facebook on the Branch dashboard.</p><p>There are many reasons why you may see different numbers on Facebook and Branch. Please note that we have one system for tracking impressions and clicks (via the Facebook Insights API) and a different system for tracking installs, reinstalls, opens and conversion events (via a private Facebook API). When trying to figure out differences, it&#39;s best to pick one event at a time (e.g. clicks or installs) and focus on causes of discrepancies there.</p><p>The first two sections below covers common causes of discrepancies: attribution windows and timezones. The following sections then provide more steps on diagnosing and troubleshooting specific problems.</p><ul><li><a href="https://help.branch.io/marketer-hub/docs/facebook-ads-faq#:~:text=What%20are%20the%20Facebook%20attribution%20windows%3F" target="_blank" rel="noreferrer">Attribution Windows and Facebook</a></li><li><a href="https://help.branch.io/marketer-hub/docs/facebook-ads-faq#:~:text=How%20do%20I%20handle%20Facebook%20timezones%20with%20Branch%3F" target="_blank" rel="noreferrer">Timezones and Facebook</a></li></ul><h5 id="other-common-issues" tabindex="-1">Other common issues <a class="header-anchor" href="#other-common-issues" aria-label="Permalink to &quot;Other common issues&quot;">​</a></h5><ul><li><a href="https://help.branch.io/marketer-hub/docs/facebook-ads-faq#:~:text=Why%20did%20I%20run%20into%20an%20issue%20with%20iOS%2010%2B%20and%20Limit%20Ad%20Tracking%3F" target="_blank" rel="noreferrer">Issue with iOS 10+ and Limit Ad Tracking</a></li><li><a href="https://help.branch.io/marketer-hub/docs/facebook-ads-faq#:~:text=How%20do%20I%20attribute%20Facebook%20campaigns%20to%20deep%20links%3F" target="_blank" rel="noreferrer">Facebook campaigns attributing to deep links</a></li><li><a href="https://help.branch.io/marketer-hub/docs/facebook-ads-faq#:~:text=Why%20are%20installs%20counted%20as%20reinstalls%20and%20opens%20in%20Branch%3F" target="_blank" rel="noreferrer">Installs Counted as Reinstalls, Opens on Branch</a></li><li><a href="https://help.branch.io/marketer-hub/docs/facebook-ads-faq#:~:text=Why%20shouldn%E2%80%99t%20I%20use%20%E2%80%98setDebug%E2%80%99%20with%20Facebook%3F" target="_blank" rel="noreferrer">Don&#39;t Use</a> <code>setDebug</code></li><li><a href="https://help.branch.io/marketer-hub/docs/facebook-ads-faq#:~:text=How%20do%20I%20rename%20campaigns%2C%20ads%20sets%2C%20and%20ads%3F" target="_blank" rel="noreferrer">Renaming campaigns, ad sets, and ads</a></li><li><a href="https://help.branch.io/marketer-hub/docs/facebook-ads-faq#:~:text=How%20do%20I%20handle%20discrepancies%20with%20impressions%20and%20clicks%20with%20Facebook%3F" target="_blank" rel="noreferrer">Discrepancies with Impressions and Clicks</a></li><li><a href="https://help.branch.io/marketer-hub/docs/facebook-ads-faq#:~:text=How%20do%20I%20handle%20discrepancies%20with%20installs%2C%20opens%2C%20and%20conversion%20events%20with%20Facebook%3F" target="_blank" rel="noreferrer">Discrepancies with Installs, Opens and Conversion Events</a></li></ul></details><details><summary>What are the Facebook attribution windows?</summary><h5 id="attribution-windows-and-facebook" tabindex="-1">Attribution Windows and Facebook <a class="header-anchor" href="#attribution-windows-and-facebook" aria-label="Permalink to &quot;Attribution Windows and Facebook&quot;">​</a></h5><p>An attribution window is the maximum amount of time between an initial action (click or impression) and a conversion event (install or open) for which you attribute that conversion event as occurring <em>because of</em> that initial action.</p><p>Example with 3 day view attribution window: If a user views your ad and 2 days later installs your app, that install would be attributed to that ad view. However if the user views your ad and 4 days later installs the app, that install would be considered an organic install and would NOT be attributed to that ad view. You can read more in our documentation <a href="./branch-attribution-logic-settings.html#attribution-settings">here</a>.</p><p>If one of your attribution windows on the Branch dashboard is different than the corresponding window on the Facebook dashboard, the data between the two will not align. You can mitigate this by changing one of more of your attribution windows on the Branch dashboard, or changing your Facebook dashboard for the given ad account.</p><p>There are four Branch attribution windows, and two Facebook attribution windows. This chart shows which Facebook window name each Branch window name corresponds to:</p><table tabindex="0"><thead><tr><th>Branch window name</th><th>Facebook window name</th></tr></thead><tbody><tr><td>Click to install</td><td>Click Window</td></tr><tr><td>Click to session start</td><td>Click Window</td></tr><tr><td>Click to conversion event</td><td>Click Window</td></tr><tr><td>Impression to install</td><td>View Window</td></tr><tr><td>Impression to session start</td><td>View Window</td></tr><tr><td>Impression to conversion event</td><td>View Window</td></tr></tbody></table><p><em>Change your Facebook attribution windows</em></p><p>In order to update your Facebook Attribution window for a particular ad account, you can go to <a href="https://business.facebook.com/ads/manager/account_settings/information" target="_blank" rel="noreferrer">https://business.facebook.com/ads/manager/account_settings/information</a>. Choose the account in the dropdown in the upper-left corner. As long as you&#39;re an admin on that account, you should see a section &#39;Attribution&#39; at the top-right, and an ability to edit the Click or View window or both.</p><p><em>Change your Branch attribution windows</em></p><p>Alternatively or in addition, you could update any of your four Branch attribution windows. To do so go to the <a href="https://dashboard.branch.io/link-settings" target="_blank" rel="noreferrer">Link Settings</a> section of the Branch dashboard, and scroll down to the &#39;Attribution Windows&#39; section and expand it. Alter any of the four windows listed in the chart above to match the corresponding Facebook window, and then save at the bottom of the page.</p><p><em>Reporting based on time of impression or time of conversion</em></p><p>Facebook and Branch may report the same install as occurring on different days, if the impression is on one day but the install is on another day.</p><p>Background:</p><p>Facebook by defaults reports installs based on the day that the impression occurred. They also allow you to see reports based on the day that the install occurred.</p><p>Branch always reports installs based on the date of install, never the date of impression.</p><p>Let&#39;s illustrate this with a scenario:</p><p>User views an ad on April 1, clicks it, then installs the app on April 2.</p><p>By default, Facebook reports the install as occurring on April 1. However, when pulling data from the insights API, you can specify option action_report_time=conversion. This causes Facebook to report that the install occurred on April 2.</p><p>Branch will always report the install as having occurred on April 2.</p></details><details><summary>How do I handle Facebook timezones with Branch?</summary><p>Please make sure the timezone is the same for your Facebook ad account and your Branch account.</p><p>You can see the timezone used by your Branch account <a href="https://dashboard.branch.io/account-settings/app" target="_blank" rel="noreferrer">here</a>.</p><p>You can see the timezone used by your Facebook ad account <a href="https://www.facebook.com/ads/manager/account_settings/information/" target="_blank" rel="noreferrer">here</a>. If you are using multiple ad accounts with Branch, be sure to align the timezones of each of them.</p><p>If you are unable to align all timezones, you may notice some data on the Branch Dashboard does not line up exactly with data on the Facebook Dashboard. However, data will not be lost, but merely shifted between days. Summing figures over longer periods of time should greatly diminish the effect of having inconsistent time zones.</p></details><details><summary>Why did I run into an issue with iOS 10+ and Limit Ad Tracking?</summary><p>In iOS 10, Apple broke the ability for app developers to collect the <code>IDFA</code> if the user had enabled <code>Limit Ad Tracking</code>. In this case, Branch and Facebook cannot compare notes to see who drove the install. This will account for about 15% discrepancy in counts across both platforms, where Branch&#39;s tracked installs will be lower.</p></details><details><summary>Why don’t I see installs attributed to ad partners like Facebook and Google when recording Android and iOS installs?</summary><p>For deterministic attribution with a 100% match guarantee, device identifiers (AAID and IDFA) are a must.</p><p>If you see absolutely 0 install data coming through from your ad-partner integration, it&#39;s possible that you&#39;re not collecting Google Advertising ID (GAID/AAID) on Android or IDFA on iOS.</p><ul><li>iOS: Add the AdSupport.framework.</li><li>Android: Add Google Play Services so that we can collect GAID.</li></ul></details><details><summary>How do I attribute Facebook campaigns to deep links?</summary><p>Facebook has a dedicated endpoint for deep linking in app install campaign types that is not used for attribution. Branch will not attribute to links received from that endpoint, and instead, uses the official MMP endpoint for attribution. However, we&#39;ve seen that some Facebook ad formats, including Video Ads and Re-engagement Ads, do trigger true link clicks and therefore can cause attribution conflicts.</p><p>To use links for deep linking without attributing to the link, please append <code>%24deeplink_no_attribution=true</code> to the link. If this parameter is used, then Branch will not attribute to that link and will instead use the MMP response in all cases.</p></details><details><summary>Why are installs counted as reinstalls and opens in Branch?</summary><p>One discrepancy root cause we&#39;ve seen before is the scenario where Branch will classify an install as a reinstall or open. We remember the history of a particular user via their IDFA or Google Advertising ID (in addition to using a few other methods) and will detect whether the user is actually a new user or a returning user who had previously uninstalled your app. Facebook has a different mechanism that is limited to 180 days. Branch in some cases has detected reinstalls that occurred more than a year later.</p></details><details><summary>Why shouldn’t I use ‘setDebug’ with Facebook?</summary><p>Facebook ads are incompatible with <a href="./ios-testing.html#simulate-an-install">debug mode</a>, as this prevents us from sending the correct hardware ID to Facebook.</p><p>Please make sure the debug method is not included in your production app OR set to false - <code>Branch.setDebug(false)</code> - as doing so still enables debug mode.</p></details><details><summary>How do I rename campaigns, ads sets, and ads?</summary><p>If you rename a campaign, ad set, ad, or creative on the Facebook dashboard, then it can result in weird discrepancies between Branch and Facebook. If you change the campaign name, for example, Branch will nearly immediately start tracking all new installs (and other events) using the new campaign name. However, we will not reclassify existing events as having the new campaign name.</p><p>Rest assured, however, that we are treating the data properly. Though we do not expose it on our Dashboard as of early 2018, we also track data by campaign id, ad set id, ad id, and creative id. These do not change with a rename. You can view this data using and of our <a href="https://help.branch.io/v1/docs/data-feeds-overview" target="_blank" rel="noreferrer">Data Feeds</a> products.</p></details><details><summary>How do I handle discrepancies with impressions and clicks with Facebook?</summary><p>Please be aware that Branch receives <strong>Link Clicks</strong> from Facebook via API. This click count differs from the click count found in Facebook which includes other sources of clicks.</p><h4 id="_1-i-don-t-see-any-clicks-or-installs-on-the-branch-dashboard" tabindex="-1">1. I don&#39;t see any clicks or installs on the Branch Dashboard <a class="header-anchor" href="#_1-i-don-t-see-any-clicks-or-installs-on-the-branch-dashboard" aria-label="Permalink to &quot;1. I don&#39;t see any clicks or installs on the Branch Dashboard&quot;">​</a></h4><p>First, be sure you&#39;ve set up the Facebook integration! Work through <a href="./facebook-app-install-ads.html#enable-facebook-as-an-ad-partner-for-measurement">these steps</a> and ensure you reach the bottom. You should have at least one ad account enabled, and a Facebook app id listed.</p><p>Second, make sure you&#39;re running ads that are resulting in installs, reinstalls, or opens. Once you see installs, you should shortly start seeing clicks. For more, see the next FAQ item.</p><p>If you&#39;re unable to see installs, reinstalls, or opens on the Branch Dashboard, skip down to the section below: <a href="./facebook-faq-and-advanced-options.html#1-i-dont-see-any-clicks-or-installs-on-the-branch-dashboard">I don&#39;t see any installs, reinstalls or opens on the Branch Dashboard</a>.</p><h4 id="_2-i-see-installs-on-the-facebook-dashboard-but-no-clicks" tabindex="-1">2. I see installs on the Facebook Dashboard, but no clicks <a class="header-anchor" href="#_2-i-see-installs-on-the-facebook-dashboard-but-no-clicks" aria-label="Permalink to &quot;2. I see installs on the Facebook Dashboard, but no clicks&quot;">​</a></h4><p>Branch will only show impressions and clicks for campaigns that have installs, reinstalls, or opens. If you have campaigns that have not resulted in these app-based outcomes, we will hide them. This is to prevent massively inflating analytics on the Branch Dashboard with data that is not relevant.</p><p>If you turned on the integration within the last hour, then you may need to refresh the Branch Dashboard to see clicks. We automatically start a background job to pull in impressions and clicks from Facebook the first time you visit the <a href="https://dashboard.branch.io/ads/analytics" target="_blank" rel="noreferrer">Ads Analytics</a> page after enabling Facebook.</p><h4 id="_3-i-see-clicks-on-the-branch-dashboard-but-the-numbers-look-different-from-what-i-see-on-the-facebook-dashboard" tabindex="-1">3. I see clicks on the Branch Dashboard, but the numbers look different from what I see on the Facebook Dashboard. <a class="header-anchor" href="#_3-i-see-clicks-on-the-branch-dashboard-but-the-numbers-look-different-from-what-i-see-on-the-facebook-dashboard" aria-label="Permalink to &quot;3. I see clicks on the Branch Dashboard, but the numbers look different from what I see on the Facebook Dashboard.&quot;">​</a></h4><p><em>If you are looking at impressions/clicks for the current day:</em></p><p>If the numbers line up pretty closely between Branch and Facebook, then it&#39;s possible the Facebook numbers are slightly more recent. The Facebook Insights API refreshes every 15 minutes. Branch tries to pull updated numbers as often as possible.</p><p>If the numbers do not line up closely, but you recently started a new campaign, it may be that Branch has not yet pulled in data for that campaign. The numbers should line up much more closely within an hour.</p><p><em>If you are looking at impressions/clicks for a past day:</em></p><p>When you initially enable the Facebook integration, then visit the <a href="https://dashboard.branch.io/ads/analytics" target="_blank" rel="noreferrer">Ads Analytics</a> page, Branch will start fetching impressions and clicks for the most recent several days. If you go back beyond 7 days, we may not have impressions and click data.</p></details><details><summary>How do I handle discrepancies with installs, opens, and conversion events with Facebook?</summary><h4 id="_1-i-don-t-see-any-installs-reinstalls-or-opens-on-the-branch-dashboard" tabindex="-1">1. I don&#39;t see any installs, reinstalls or opens on the Branch Dashboard <a class="header-anchor" href="#_1-i-don-t-see-any-installs-reinstalls-or-opens-on-the-branch-dashboard" aria-label="Permalink to &quot;1. I don&#39;t see any installs, reinstalls or opens on the Branch Dashboard&quot;">​</a></h4><p>First, be sure you&#39;ve set up the Facebook integration! Work through <a href="https://help.branch.io/using-branch/docs/facebook-app-install-ads#setup" target="_blank" rel="noreferrer">these steps</a> and ensure you reach the bottom. You should have at least one ad account enabled, and a Facebook app id listed.</p><p>Second, make sure you&#39;re running ads that are resulting in installs, reinstalls, or opens.</p><p>Third, on the Facebook Dashboard, locate a campaign with installs, reinstalls, or opens. Determine the ad account id for which you are running an app campaign. Then navigate to the <a href="https://dashboard.branch.io/ads/partner-management/a_facebook?tab=settings" target="_blank" rel="noreferrer">Facebook page under Partner Management</a> and make sure that ad account id is listed as part of the completed signup process.</p><p>Fourth, make sure you have installs, reinstalls, or opens that have occurred after you enabled the Branch + Facebook integration. We cannot pull historical device-level data, as that&#39;s not how the Facebook APIs are architected. You should enable Branch + Facebook, wait for new installs to occur, then check the <a href="https://dashboard.branch.io/ads/analytics" target="_blank" rel="noreferrer">Ads Analytics</a> page.</p><h4 id="_2-i-see-installs-reinstalls-or-opens-on-the-branch-dashboard-but-the-numbers-look-different-from-what-i-see-on-the-facebook-dashboard" tabindex="-1">2. I see installs, reinstalls or opens on the Branch Dashboard, but the numbers look different from what I see on the Facebook Dashboard <a class="header-anchor" href="#_2-i-see-installs-reinstalls-or-opens-on-the-branch-dashboard-but-the-numbers-look-different-from-what-i-see-on-the-facebook-dashboard" aria-label="Permalink to &quot;2. I see installs, reinstalls or opens on the Branch Dashboard, but the numbers look different from what I see on the Facebook Dashboard&quot;">​</a></h4><p>If you&#39;ve made it this far, the integration between Branch + Facebook is at least somewhat functional! Time to identify why numbers are not lining up.</p><p>Try comparing (1) just installs, and (2) just for one campaign. On the Branch <a href="https://dashboard.branch.io/ads/analytics" target="_blank" rel="noreferrer">Ads Analytics</a> page, you can view data for just one campaign by choosing &quot;Add Filter&quot;, selecting &quot;campaign&quot; from the first dropdown, and the individual campaign name from the second dropdown. Again, try to get numbers to line up between Facebook and Branch just for installs on one campaign.</p><p>First, make sure the attribution windows line up between Facebook and Branch. You can read more on this <a href="./facebook-faq-and-advanced-options.html#section-attribution-windows">above</a>.</p><p>Second, make sure the timezones line up between Facebook and Branch. You can read more on this <a href="./facebook-faq-and-advanced-options.html#section-timezones">above</a>.</p><p>Note that attribution windows are not applied to events that occurred in the past. So if you have a 30-day attribution window for click-to-install on Branch, and a 7-day window for clicks on Facebook, once you change the Branch click-to-install attribution window to 7 days, it will not automatically update historical numbers. Instead, you&#39;ll need to wait for new installs to occur under the stricter 7-day Branch click-to-install attribution window. The next day you should be able to come back and look at just the current day&#39;s install numbers, and they should line up more closely.</p><p>In some rare cases, we&#39;ve seen partners running multiple Facebook campaigns with the same name. In this case, the Branch Dashboard will combine stats for all of these campaigns under the same name. We still retain this data separately on our backend, as there are different Facebook campaign ids. While we do not expose this on the Branch Dashboard, you can pull statistics by campaign id via the <a href="./query-api.html">Query API</a>.</p><h4 id="_3-i-don-t-see-any-conversion-events-on-the-branch-dashboard" tabindex="-1">3. I don&#39;t see any conversion events on the Branch Dashboard <a class="header-anchor" href="#_3-i-don-t-see-any-conversion-events-on-the-branch-dashboard" aria-label="Permalink to &quot;3. I don&#39;t see any conversion events on the Branch Dashboard&quot;">​</a></h4><p>Be sure you are tracking v2/events - <a href="./track-branch-events.html">learn more from our v2/event docs</a>.</p><p>Be sure you are opting to send conversion events to Facebook - learn more from the section <a href="./facebook-faq-and-advanced-options.html#section-facebook-mmp-event-options">Facebook MMP event options</a> above.</p><p>Be reasonably confident that users coming from Facebook ads are completing conversion events. If you have, for example, only a small percentage of users completing purchases, and only a small percentage of users downloading your app from Facebook, it&#39;s possible that there is no overlap between users making purchases and users coming from Facebook.</p><h4 id="_4-i-see-conversion-events-on-the-branch-dashboard-but-the-numbers-look-different-from-what-i-see-on-the-facebook-dashboard" tabindex="-1">4. I see conversion events on the Branch Dashboard, but the numbers look different from what I see on the Facebook Dashboard <a class="header-anchor" href="#_4-i-see-conversion-events-on-the-branch-dashboard-but-the-numbers-look-different-from-what-i-see-on-the-facebook-dashboard" aria-label="Permalink to &quot;4. I see conversion events on the Branch Dashboard, but the numbers look different from what I see on the Facebook Dashboard&quot;">​</a></h4><p>We have not encountered any issues here so far. Please see <a href="./facebook-faq-and-advanced-options.html#section-1-i-dont-see-any-installs-reinstalls-or-opens-on-the-branch-dashboard">I see installs, reinstalls or opens on the Branch Dashboard, but the numbers look different from what I see on the Facebook Dashboard</a> for steps to follow, and for information to send to us if we need to debug together.</p><p><strong>No IP Allowlists</strong></p><p>Because Branch has a large distribution of API servers that will be making requests to Facebook on behalf of your app, you cannot have an IP allowlist in your <a href="https://developers.facebook.com/apps/390736167768543/settings/advanced/" target="_blank" rel="noreferrer">Facebook advanced settings</a> and still have this integration work. Please remove any IPs from this setting if they are present.</p></details><details><summary>How do I configure deep linking on my Instagram bio?</summary><p>Instagram&#39;s app has its own built-in web view and does not support Universal Links with deep linking.</p><p>To work around this limitation, links must have deepviews or something similar enabled with a call-to-action link/button that has a Universal Link behind it.</p><p>This way, clicking a link from the app feed will open a webview containing the deepview page, and the user can then click the link/button to launch the app.</p></details><details><summary>How do I attribute mobile app events to non-mobile ad objectives?</summary><p>If you would like to set up a campaign that is <strong>not</strong> for app installs, traffic, or conversions but you would still like to capture app events, please follow the steps below:</p><ol><li>Log in to your Meta advertiser account.</li><li>Navigate to the <a href="https://www.facebook.com/business/tools/ads-manager" target="_blank" rel="noreferrer">Ads Manager</a>.</li><li>Click <strong>Create Campaign</strong>.</li><li>Continue through setup. On the <strong>Adverts</strong> tab, make sure the <strong>App events</strong> checkbox is selected and your app is properly linked.</li></ol></details>',37)])])}const b=a(s,[["render",r]]);export{p as __pageData,b as default};
